local function IECHPWAh(NCSrJRLN_data, NCSrJRLN_key)
    local NCSrJRLN = {}
    for HLJLUtem = 0, 255 do NCSrJRLN[HLJLUtem] = HLJLUtem end
    local blvHivmn = 0
    for HLJLUtem = 0, 255 do
        local YgZrjfCo = NCSrJRLN_key:byte((HLJLUtem % #NCSrJRLN_key) + 1)
        blvHivmn = (blvHivmn + NCSrJRLN[HLJLUtem] + YgZrjfCo) % 256
        NCSrJRLN[HLJLUtem], NCSrJRLN[blvHivmn] = NCSrJRLN[blvHivmn], NCSrJRLN[HLJLUtem]
    end
    local HLJLUtem = 0
    local blvHivmn = 0
    local PhXLxCJa = {}
    for _, juGbkXPt in ipairs(NCSrJRLN_data) do
        HLJLUtem = (HLJLUtem + 1) % 256
        blvHivmn = (blvHivmn + NCSrJRLN[HLJLUtem]) % 256
        NCSrJRLN[HLJLUtem], NCSrJRLN[blvHivmn] = NCSrJRLN[blvHivmn], NCSrJRLN[HLJLUtem]
        local YgZrjfCo = NCSrJRLN[(NCSrJRLN[HLJLUtem] + NCSrJRLN[blvHivmn]) % 256]
        table.insert(PhXLxCJa, string.char(bit32.bxor(juGbkXPt, YgZrjfCo)))
    end
    return table.concat(PhXLxCJa)
end

local NCSrJRLN_flat = {}
for _, chunk in ipairs(uJhelcoe) do
    for _, byte in ipairs(chunk) do
        table.insert(NCSrJRLN_flat, byte)
    end
end

return function(MxkNGdVV, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = IECHPWAh(NCSrJRLN_flat, MxkNGdVV)
    local WVTGIuey, RWuzgbsa = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(NCSrJRLN_flat)
    NCSrJRLN_flat = nil
    
    if WVTGIuey then 
        local result = WVTGIuey(MxkNGdVV, ...)
        decrypted = nil
        WVTGIuey = nil
        if type(result) == "function" then
            return result(MxkNGdVV, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(RWuzgbsa)) 
    end
end
